export const Sidebar: React.FC = () => {
  const location = useLocation();
  // State to manage open groups. Default 'Operación' to open if we are in a child route, or closed otherwise.
  const [openGroups, setOpenGroups] = useState<string[]>([]);

  // Auto-open group if active route is inside it
  useEffect(() => {
    const operationPaths = ['/inventory', '/inventory-control', '/production'];
    if (operationPaths.includes(location.pathname)) {
        setOpenGroups(prev => prev.includes('Operación') ? prev : [...prev, 'Operación']);
    }
  }, [location.pathname]);

  const toggleGroup = (groupLabel: string) => {
    setOpenGroups(prev => 
        prev.includes(groupLabel) 
        ? prev.filter(g => g !== groupLabel) 
        : [...prev, groupLabel]
    );
  };

  const navStructure = [
    { type: 'item', to: "/", icon: LayoutDashboard, label: "Tablero Principal" },
