export default App;

export enum InventoryStatus {
  ACTIVE = 'Activo',
  SLOW = 'Lento',
  SILENT = 'Silencioso',
  DEAD = 'Obsoleto',
}

export enum Category {
  RAW_MATERIAL = 'Materia Prima',
  WIP = 'En Proceso (WIP)',
  FINISHED_GOOD = 'Producto Terminado',
}

export enum ABCClass {
  A = 'A',
  B = 'B',
  C = 'C',
}

export enum XYZClass {
  X = 'X', // Stable demand
  Y = 'Y', // Variable
  Z = 'Z', // Sporadic
}

export enum BatchStatus {
  SCHEDULED = 'Programado',
  IN_PROGRESS = 'En Proceso',
  QA_CHECK = 'Control Calidad',
  COMPLETED = 'Completado',
}

export enum CustomerTier {
  STRATEGIC = 'Estratégico',
  REGULAR = 'Regular',
  NEW = 'Nuevo',
}

export interface Customer {
  id: string;
  name: string;
  tier: CustomerTier;
  slaLevel: 'Gold' | 'Silver' | 'Bronze';
}

export interface SalesOrder {
  id: string;
  customerId: string;
  skuId: string;
  qty: number;
  orderDate: string;
  requiredDate: string;
  marginPercent: number;
  status: 'Allocated' | 'Backorder' | 'Pending';
  priorityScore: number; // Calculated field
}

export interface Batch {
  id: string;
  skuId: string;
  lotNumber: string;
  expiryDate: string;
  dateIn: string; // Entry date for precise aging
  quantity: number;
  reserved: number; // Committed stock per batch
  location: string;
}

export interface Product {
  id: string;
  sku: string;
  name: string;
  category: Category;
  unitCost: number;
  price: number;
  totalStock: number;
  reservedStock: number; // ATP = Total - Reserved
  status: InventoryStatus;
  abc: ABCClass;
  xyz: XYZClass;
  agingDays: number; // Average aging
  batches: Batch[];
}

export interface Transfer {
  id: string;
  skuId: string;
  productName: string;
  fromLocation: string;
  toLocation: string;
  quantity: number;
  status: 'Pendiente' | 'En Tránsito' | 'Recibido';
  requestDate: string;
  eta: string;
}

export interface FormulaItem {
    name: string;
    unit: string;
    plannedQty: number;
    actualQty: number; // If actual > planned, creates variance
    costImpact: number; // Value of the variance
}

export interface ProductionBatch {
    id: string;
    batchNumber: string;
    productName: string;
    sku: string;
    status: BatchStatus;
    startDate: string;
    endDate?: string;

    // Quantity Metrics
    plannedOutput: number;
    actualOutput: number;
    waste: number; // Merma in units/kg
    rework: boolean; // Was rework required?

    // Financials
    standardUnitCost: number;
    realUnitCost: number; // Calculated after deviations

    ingredients: FormulaItem[];
}

export interface SalesRecord {
  month: string;
  sales: number;
  forecast: number;
}

export interface ForecastDataPoint {
    month: string;
    historical?: number;
    conservative: number;
    base: number;
    aggressive: number;
    pipelineWeighted: number; // Sales pipeline probability weighted
}

export interface DemandAlert {
    id: string;
    sku: string;
    productName: string;
    type: 'STOCKOUT' | 'OVERSTOCK';
    projectedDate: string;
    gapQuantity: number;
    severity: 'HIGH' | 'MEDIUM' | 'LOW';
}

export type ActionType = 'LIQUIDATION' | 'TRANSFER' | 'BUNDLE' | 'SCRAP';

export interface ActionOpportunity {
    id: string;
    type: ActionType;
    skuId: string;
    productName: string;
    reason: string; // e.g., "Silent > 180 days"
    suggestedAction: string; // e.g., "Promo 20% Off"

    // Impact Analysis
    quantityToMove: number;
    potentialCashRelease: number;
    marginImpactPercent: number; // Negative for discounts
    costOfAction: number; // e.g., Logistics cost

    status: 'PENDING' | 'EXECUTED' | 'DISMISSED';
}

export interface Vendor {
    id: string;
    name: string;
    leadTimeDays: number;
    reliabilityScore: number; // 0-100
    qualityScore: number; // 0-100
    priceIndex: 'Low' | 'Medium' | 'High';
}

export interface PurchaseSuggestion {
    id: string;
    skuId: string;
    productName: string;
    suggestedQty: number;
    unitCost: number;
    totalCost: number;
    recommendedVendorId: string;
    reason: string; // e.g. "Below Reorder Point (ROP)"
    urgency: 'High' | 'Medium' | 'Low';

    // Intelligence
    forecastCoverageDays: number; // How many days of demand this buys
    riskOfOverstock: 'Low' | 'Medium' | 'High'; // Analysis of "Bad Buy"
    status: 'Proposed' | 'Approved' | 'Rejected';
}

export interface KPI {
  label: string;
  value: string;
  change: number;
  isPositive: boolean;
  unit?: string;
}

// --- EVENT LOG TYPES ---

export type EventActorType = 'HUMAN' | 'SYSTEM' | 'AI';
export type EventCategory = 'OPERATIONS' | 'PLANNING' | 'FINANCE' | 'INTELLIGENCE' | 'ERROR';
export type ConfidenceLevel = 'MANUAL' | 'ASSISTED' | 'AUTOMATIC';

export interface SystemEvent {
  event_id: string;
  event_type: string; // e.g., 'STOCK_ADJUSTMENT', 'PO_CREATED'
  event_category: EventCategory;
  entity_type: string; // 'SKU', 'ORDER', 'BATCH'
  entity_id: string;

  actor_type: EventActorType;
  actor_id: string; // 'user_123', 'system_cron', 'gemini-pro'

  timestamp: string; // ISO-8601

  previous_state: Record<string, any> | null;
  new_state: Record<string, any> | null;

  context: {
    channel: 'WEB' | 'MOBILE' | 'API' | 'SYSTEM';
    location?: string;
    reason?: string;
    meta?: Record<string, any>;
  };

  causal_chain_id: string; // ID to group related events
  confidence_level: ConfidenceLevel;
}

import React, { useState } from 'react';
import { 
    Search, Filter, Clock, User, Bot, Server, 
    AlertTriangle, CheckCircle2, DollarSign, Fingerprint, 
    ChevronRight, X, ArrowRight, GitCommit, Eye
} from 'lucide-react';
import { MOCK_EVENT_LOG } from '../constants';
import { SystemEvent, EventCategory, EventActorType } from '../types';

const EventIcon = ({ type }: { type: EventCategory | 'ERROR' }) => {
    switch (type) {
        case 'OPERATIONS': return <div className="p-2 bg-blue-100 rounded-lg text-blue-600"><Fingerprint className="w-5 h-5" /></div>;
        case 'INTELLIGENCE': return <div className="p-2 bg-purple-100 rounded-lg text-purple-600"><Bot className="w-5 h-5" /></div>;
        case 'FINANCE': return <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600"><DollarSign className="w-5 h-5" /></div>;
        case 'ERROR': return <div className="p-2 bg-rose-100 rounded-lg text-rose-600"><AlertTriangle className="w-5 h-5" /></div>;
        case 'PLANNING': return <div className="p-2 bg-amber-100 rounded-lg text-amber-600"><Clock className="w-5 h-5" /></div>;
        default: return <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><Server className="w-5 h-5" /></div>;
    }
};

const ActorBadge = ({ type, id }: { type: EventActorType, id: string }) => {
    return (
        <span className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded text-[10px] font-mono font-medium border ${
            type === 'HUMAN' ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
            type === 'AI' ? 'bg-fuchsia-50 text-fuchsia-700 border-fuchsia-200' :
            'bg-slate-50 text-slate-600 border-slate-200'
        }`}>
            {type === 'HUMAN' && <User className="w-3 h-3" />}
            {type === 'AI' && <Bot className="w-3 h-3" />}
            {type === 'SYSTEM' && <Server className="w-3 h-3" />}
            {id}
        </span>
    );
};

export const EventLog: React.FC = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [categoryFilter, setCategoryFilter] = useState<string>('ALL');
    const [selectedEvent, setSelectedEvent] = useState<SystemEvent | null>(null);

    const filteredEvents = MOCK_EVENT_LOG.filter(evt => {
        const matchesSearch = 
            evt.event_type.toLowerCase().includes(searchTerm.toLowerCase()) || 
            evt.entity_id.toLowerCase().includes(searchTerm.toLowerCase()) ||
            evt.event_id.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = categoryFilter === 'ALL' || evt.event_category === categoryFilter;
        return matchesSearch && matchesCategory;
    });

    return (
        <div className="flex h-screen bg-slate-50 overflow-hidden">

            {/* MAIN LIST AREA */}
